export function Quote() {
    return (
        <section className="py-24 sm:py-32 flex justify-center items-center px-4 relative max-w-7xl mx-auto">
            <div className="absolute top-0 left-1/2 -translate-x-1/2 w-3/4 h-px bg-gradient-to-r from-transparent via-cyan-200/50 to-transparent"></div>

            <div className="flex items-start gap-4 md:gap-6 mt-12 mb-12">
                {/* Quote Icon */}
                <div className="flex space-x-[8px] mt-2 md:mt-3 shrink-0">
                    <div className="w-[14px] md:w-[18px] h-[36px] md:h-[46px] bg-slate-200 skew-x-[-20deg]"></div>
                    <div className="w-[14px] md:w-[18px] h-[36px] md:h-[46px] bg-slate-200 skew-x-[-20deg]"></div>
                </div>

                {/* Text */}
                <div className="text-[32px] sm:text-[40px] md:text-[46px] leading-[1.3] text-slate-500 tracking-tight flex flex-col items-start font-medium">

                    {/* Line 1 */}
                    <div className="italic text-slate-500/90 font-light">Beautiful</div>

                    {/* Line 2 */}
                    <div className="flex items-center gap-3 md:gap-4 my-1">
                        <div className="w-10 sm:w-16 md:w-20 h-[1.5px] bg-slate-400"></div>
                        <span className="flex gap-[6px] md:gap-2 items-baseline">
                            <span className="font-extrabold text-slate-700">inside</span>
                            <span className="font-light">and</span>
                            <span className="font-extrabold text-slate-700">out</span>
                        </span>
                        <div className="w-10 sm:w-16 md:w-20 h-[1.5px] bg-slate-400"></div>
                    </div>

                    {/* Line 3 */}
                    <div className="flex items-center gap-2 md:gap-3 mt-1">
                        <span className="font-light">is a</span>
                        <span className="font-extrabold text-slate-700 bg-slate-100 px-4 py-1.5 md:py-2 rounded-[0.5rem] ml-1 shadow-sm leading-none flex items-center justify-center">
                            must.
                        </span>
                    </div>

                </div>
            </div>
        </section>
    );
}
